import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"新股申购","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"ipo/subscription.md","filePath":"zh-CN/ipo/subscription.md"}'),l={name:"ipo/subscription.md"};function o(h,a,d,n,p,s){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="新股申购" tabindex="-1">新股申购 <a class="header-anchor" href="#新股申购" aria-label="Permalink to &quot;新股申购&quot;">​</a></h1><p>新股认购（打新股/抽新股）是指公司首次公开募股（IPO）时，公开发售给普通投资者的股票认购过程。投资者有机会以发行价购买新上市公司的股票。</p><p>目前仅支持打新港股，不支持美股。</p><p>重要提示：港股打新不可以多券商递交申请，重复申请会被港交所拒绝，这是港交所的规定。</p><h2 id="认购方式" tabindex="-1">认购方式 <a class="header-anchor" href="#认购方式" aria-label="Permalink to &quot;认购方式&quot;">​</a></h2><p>支持两种认购方式（二选一，不可同时申请）：</p><ul><li><strong>普通认购</strong>：使用账户持仓抵押融资、可用现金进行认购</li><li><strong>银行融资认购</strong>：使用股票质押融资 + 最高 33 倍杠杆银行融资</li></ul><h2 id="认购流程" tabindex="-1">认购流程 <a class="header-anchor" href="#认购流程" aria-label="Permalink to &quot;认购流程&quot;">​</a></h2><ol><li>长桥 App - 市场 - 新股，进入新股认购列表页</li><li>在认购中的新股点击「立即认购」，选择认购方式和认购股数</li><li>点击「申请认购」，确认订单后提交</li><li>在新股页「认购记录」查看认购状态</li></ol><p>认购截止前支持改单和撤销，入口：长桥 App - 市场 - 新股 - 认购记录。</p><p>当天卖出的股票可用于认购下单，但卖出资金通常 T+2 结算，若扣款日未结算完成会产生借币融资。当天入金的资金需到账后方可使用；账户有欠款时资金优先还款，还清后可用持仓抵押认购。</p><h2 id="认购时间" tabindex="-1">认购时间 <a class="header-anchor" href="#认购时间" aria-label="Permalink to &quot;认购时间&quot;">​</a></h2><p>普通认购：通常于公开截止日当天早上 09:00 截止<br> 银行融资认购：通常于公开截止日的上一个交易日早上 11:00 截止（具体以认购页面显示为准）</p><h2 id="公布中签时间" tabindex="-1">公布中签时间 <a class="header-anchor" href="#公布中签时间" aria-label="Permalink to &quot;公布中签时间&quot;">​</a></h2><p>认购结果于上市前一个交易日当天下午 16:00 前公布。中签信息通过 App 消息通知推送，也可在消息中心 - 交易变动和认购记录详情中查询。</p><p>香港身份证明文件开户的客户可通过披露易网站查询，其他国家/地区客户可能因证件问题无法在披露易查询。</p><h2 id="收费标准" tabindex="-1">收费标准 <a class="header-anchor" href="#收费标准" aria-label="Permalink to &quot;收费标准&quot;">​</a></h2><h3 id="认购手续费" tabindex="-1">认购手续费 <a class="header-anchor" href="#认购手续费" aria-label="Permalink to &quot;认购手续费&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>手续费</th></tr></thead><tbody><tr><td>普通认购</td><td>49 HKD / 笔</td></tr><tr><td>银行融资认购</td><td>常规 99 HKD / 笔（以认购页面为准）</td></tr><tr><td>手续费无论是否中签均需缴纳，在认购截止日扣除。如遇新股延期或取消上市，手续费不退还。</td><td></td></tr></tbody></table><h3 id="中签费用" tabindex="-1">中签费用 <a class="header-anchor" href="#中签费用" aria-label="Permalink to &quot;中签费用&quot;">​</a></h3><p>中签收取总计 1.0085%（含经纪佣金 1%、香港证监会 0.0027%、交易所 0.00565%、财汇局 0.00015%）。</p><h2 id="扣款时间" tabindex="-1">扣款时间 <a class="header-anchor" href="#扣款时间" aria-label="Permalink to &quot;扣款时间&quot;">​</a></h2><h3 id="普通认购" tabindex="-1">普通认购 <a class="header-anchor" href="#普通认购" aria-label="Permalink to &quot;普通认购&quot;">​</a></h3><p>认购资金在发起申请后实时冻结，于认购截止日扣除。</p><h3 id="银行融资认购" tabindex="-1">银行融资认购 <a class="header-anchor" href="#银行融资认购" aria-label="Permalink to &quot;银行融资认购&quot;">​</a></h3><ul><li>本金部分：申请后实时冻结，认购截止日扣款（通常提前 1 个交易日）</li><li>银行融资部分：提交时先记账，公布中签日统一扣款</li><li>银行融资利息：无论是否中签均需缴纳，在公布中签日扣除</li></ul><h2 id="融资额度与利息" tabindex="-1">融资额度与利息 <a class="header-anchor" href="#融资额度与利息" aria-label="Permalink to &quot;融资额度与利息&quot;">​</a></h2><p>港股新股申购最高支持 33 倍融资，以新股认购时的倍数为准。银行融资认购账户至少需要 3% 的港币现金（最大融资比例为认购额的 97%），银行融资部分不能提前还款，将在公布中签日依据中签结果实际扣款。</p><p>银行融资利息从认购截止日起至中签结果公布前一日止收取。</p><p>计息公式：日利息 = 融资额 ×（银行融资利率 ÷ 365）</p><p>利息与申请早晚无关，均从认购截止日开始计息。如遇新股延期或取消上市，计息时长相应增加。</p><p>中签后如账户保证金比例不足会触发 Margin Call，须在上市交易日下午 14:00 前存入足额保证金，否则中签新股可能被强平。</p><h2 id="资金退回" tabindex="-1">资金退回 <a class="header-anchor" href="#资金退回" aria-label="Permalink to &quot;资金退回&quot;">​</a></h2><h3 id="未中签" tabindex="-1">未中签 <a class="header-anchor" href="#未中签" aria-label="Permalink to &quot;未中签&quot;">​</a></h3><p>扣除的认购额本金在公布中签日退回账户。</p><h3 id="部分中签" tabindex="-1">部分中签 <a class="header-anchor" href="#部分中签" aria-label="Permalink to &quot;部分中签&quot;">​</a></h3><p>中签部分增加持仓，未中签的多扣部分资金在中签结果公布后退回。</p><h3 id="全部中签" tabindex="-1">全部中签 <a class="header-anchor" href="#全部中签" aria-label="Permalink to &quot;全部中签&quot;">​</a></h3><p>增加持仓，在暗盘时间可正常交易。</p><h2 id="中签机制" tabindex="-1">中签机制 <a class="header-anchor" href="#中签机制" aria-label="Permalink to &quot;中签机制&quot;">​</a></h2><p>港股打新由抽签决定，规则由港交所制定。认购数量越多不代表中签概率越高。中签结果于上市前一个交易日 16:00 前公布。</p>',41)])])}const b=t(l,[["render",o]]);export{u as __pageData,b as default};
